import { cn } from './utils';
import * as ProgressPrimitive from '@radix-ui/react-progress';

function Progress({
  className,
  value,
  colorClass = 'bg-primary2',
  ...props
}: React.ComponentProps<typeof ProgressPrimitive.Root>) {
  return (
    <ProgressPrimitive.Root
      data-slot="progress"
      className={cn(
        "bg-primary2/20 relative h-2 w-full overflow-hidden rounded-full",
        className,
      )}
      {...props}
    >
      <ProgressPrimitive.Indicator
        data-slot="progress-indicator"
        // className="bg-primary2 h-full w-full flex-1 transition-all"
        className={cn(colorClass, "h-full w-full flex-1 transition-all")}
        style={{ transform: `translateX(-${100 - (value || 0)}%)` }}
      />
    </ProgressPrimitive.Root>
  );
}

export { Progress };
